oxy_webhelp_navlinks = {"mt_ded_tenant-d30753e55821":{"topics":[{"title":"Service provider capabilities","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> multi-account management provides service providers with         tools to provision isolated dedicated tenants, manage shared licenses, and access advanced         security features across all client environments.<\/p>","href":"saas\/mt_dt_msp_capabilities.html","attributes":{"data-id":"mt_dt_msp_capabilities"},"menu":{"hasChildren":false},"tocID":"mt_dt_msp_capabilities-d30753e55838","topics":[]},{"title":"Dedicated tenant creation prerequisites","shortdesc":"<p class=\"shortdesc\">Before creating and managing dedicated <span class=\"ph\">Rubrik Security Cloud<\/span> tenants, it is         important to ensure that the primary account meets specific account type, licensing, and         administrative role requirements to ensure necessary isolation and resource allocation         across tenant accounts.<\/p>","href":"saas\/mt_dt_creation_prereqs.html","attributes":{"data-id":"mt_dt_creation_prereqs"},"menu":{"hasChildren":false},"tocID":"mt_dt_creation_prereqs-d30753e55851","topics":[]},{"title":"Dedicated tenant creation limitations","shortdesc":"<p class=\"shortdesc\">Dedicated <span class=\"ph\">RSC<\/span> tenant management involves specific restrictions         regarding administrative ownership, account nesting, regional availability, and license         dependencies.<\/p>","href":"saas\/mt_dt_creation_limits.html","attributes":{"data-id":"mt_dt_creation_limits"},"menu":{"hasChildren":false},"tocID":"mt_dt_creation_limits-d30753e55865","topics":[]},{"title":"Supported regions for dedicated tenants","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> supports specific geographic regions for provisioning         dedicated tenant accounts to ensure compliance with data residency requirements and         infrastructure availability.<\/p>","href":"saas\/mt_dt_sup_regions.html","attributes":{"data-id":"mt_dt_sup_regions"},"menu":{"hasChildren":false},"tocID":"mt_dt_sup_regions-d30753e55879","topics":[]},{"title":"Creating a dedicated tenant","shortdesc":"<p class=\"shortdesc\">Create a dedicated <span class=\"ph\">RSC<\/span> tenant to provide users with a physically         isolated <span class=\"ph\">RSC<\/span> instance that supports full feature parity and independent         management.<\/p>","href":"saas\/mt_dt_create.html","attributes":{"data-id":"mt_dt_create"},"menu":{"hasChildren":false},"tocID":"mt_dt_create-d30753e55892","topics":[]},{"title":"Granular access control for dedicated tenant management","shortdesc":"<p class=\"shortdesc\">Granular access control lets a Global Administrator delegate dedicated tenant         management to non-administrator users in the primary <span class=\"ph\">RSC<\/span> account by         assigning view or create-and-edit permissions to custom roles.<\/p>","href":"saas\/mt_dt_access_control.html","attributes":{"data-id":"mt_dt_access_control"},"menu":{"hasChildren":false},"tocID":"mt_dt_access_control-d30753e55909","next":"mt_dt_access_control-d30753e55909"},{"title":"Retrying provisioning for failed accounts","shortdesc":"<p class=\"shortdesc\">Retry the provisioning process for a dedicated tenant account that failed during the         initial setup.<\/p>","href":"saas\/mt_dt_retry_prov_failed_accounts.html","attributes":{"data-id":"mt_dt_retry_prov_failed_accounts"},"menu":{"hasChildren":false},"tocID":"mt_dt_retry_prov_failed_accounts-d30753e55965","topics":[]},{"title":"Retrying product provisioning for dedicated tenants","shortdesc":"<p class=\"shortdesc\">Retry product provisioning for dedicated tenants by identifying failed products and         monitoring Product Status to ensure successful deployment.<\/p>","href":"saas\/mt_dt_retry_prov_product.html","attributes":{"data-id":"mt_dt_retry_prov_product"},"menu":{"hasChildren":false},"tocID":"mt_dt_retry_prov_product-d30753e55976","topics":[]},{"title":"Managing licenses for dedicated tenants","shortdesc":"<p class=\"shortdesc\">Manage licenses for dedicated tenants by allocating licenses from a shared pool to         enable data protection and security services.<\/p>","href":"saas\/mt_dt_mng_licenses.html","attributes":{"data-id":"mt_dt_mng_licenses"},"menu":{"hasChildren":false},"tocID":"mt_dt_mng_licenses-d30753e55987","topics":[]},{"title":"Dedicated tenant metrics","shortdesc":"<p class=\"shortdesc\">The Dedicated Tenants dashboard provides a centralized view of account status,         products provisioned, and regional distribution for all tenant accounts.<\/p>","href":"saas\/mt_dt_metrics.html","attributes":{"data-id":"mt_dt_metrics"},"menu":{"hasChildren":false},"tocID":"mt_dt_metrics-d30753e55998","topics":[]},{"title":"Dedicated tenant suspension and resumption","shortdesc":"<p class=\"shortdesc\">Primary account users with the <span class=\"ph uicontrol\">Suspend and Resume Dedicated Tenant             Accounts<\/span> permission can temporarily block a dedicated <span class=\"ph\">Rubrik Security Cloud<\/span> tenant's users and admins from the UI and API while data protection operations continue,         and these users can restore access at any time.<\/p>","href":"saas\/mt_dt_suspending_unsuspending.html","attributes":{"data-id":"mt_dt_suspending_unsuspending"},"menu":{"hasChildren":false},"tocID":"mt_dt_suspending_unsuspending-d30753e56010","next":"mt_dt_suspending_unsuspending-d30753e56010"}]}};